module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);

    parameter S_IDLE = 2'd0;
    parameter S_DIVIDE = 2'd1;
    parameter S_DONE = 2'd2;
    reg [1:0] state, next_state;
    reg [3:0] cnt, next_cnt;
    reg [15:0] SR, next_SR;
    reg [15:0] NEG_DIVISOR, next_NEG_DIVISOR;
    reg [15:0] result_reg, next_result_reg;
    reg next_res_valid;
    wire [16:0] sub_result;
    wire sub_carry;

    assign sub_result = (sub_carry = (NEG_DIVISOR[16] == 1'b0)) ? SR - NEG_DIVISOR : 17'b11111111111111111;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= S_IDLE;
        end
        else begin
            state <= next_state;
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            cnt <= 4'd0;
        end
        else begin
            cnt <= next_cnt;
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            SR <= 16'd0;
        end
        else begin
            SR <= next_SR;
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            NEG_DIVISOR <= 16'd0;
        end
        else begin
            NEG_DIVISOR <= next_NEG_DIVISOR;
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            result_reg <= 16'd0;
        end
        else begin
            result_reg <= next_result_reg;
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 1'b0;
        end
        else begin
            res_valid <= next_res_valid;
        end
    end

    always @(*) begin
        next_state = state;
        next_cnt = cnt;
        next_SR = SR;
        next_NEG_DIVISOR = NEG_DIVISOR;
        next_result_reg = result_reg;
        next_res_valid = res_valid;
        case (state)
            S_IDLE: begin
                if (opn_valid && !res_valid) begin
                    next_state = S_DIVIDE;
                    next_cnt = 4'd0;
                    next_SR = (dividend[15] == 1'b0) ? {9'b000000000, dividend} : {9'b000000000, (~dividend + 1'b1)};
                    next_NEG_DIVISOR = (divisor[15] == 1'b0) ? {1'b0, ~divisor + 1'b1} : {1'b1, divisor};
                    next_result_reg = 16'd0;
                    next_res_valid = 1'b1;
                end
            end
            S_DIVIDE: begin
                if (cnt == 4'd15) begin
                    next_state = S_DONE;
                    next_cnt = 4'd0;
                    next_SR = (SR[15] == 1'b0) ? {SR[14:0], 1'b0} : {SR[14:0], 1'b0} + 1'b1;
                    next_NEG_DIVISOR = (divisor[15] == 1'b0) ? {1'b0, ~divisor + 1'b1} : {1'b1, divisor};
                    next_result_reg = (sign == 1'b1 && dividend[15] != divisor[15]) ? {SR[15], SR[15:0], ~result_reg + 1'b1} + 1'b1 : {SR[15], SR[15:0], result_reg};
                    next_res_valid = 1'b1;
                end
                else begin
                    next_cnt = cnt + 4'd1;
                    next_SR = (sub_carry == 1'b1) ? {SR[14:0], 1'b0} : {SR[14:0], 1'b0} + 1'b1;
                    next_NEG_DIVISOR = (divisor[15] == 1'b0) ? {1'b0, ~divisor + 1'b1} : {1'b1, divisor};
                    next_result_reg = (sign == 1'b1 && dividend[15] != divisor[15]) ? {SR[15], SR[15:0], ~result_reg + 1'b1} + 1'b1 : {SR[15], SR[15:0], result_reg};
                    next_res_valid = 1'b0;
                end
            end
            S_DONE: begin
                if (res_ready) begin
                    next_state = S_IDLE;
                    next_cnt = 4'd0;
                    next_SR = 16'd0;
                    next_NEG_DIVISOR = 17'd0;
                    next_result_reg = 16'd0;
                    next_res_valid = 1'b0;
                end
            end
        endcase
    end
    assign result = result_reg;
endmodule
